	if rr, ok := r.r.(contentNodeBuildStateResetter); ok {
		rr.resetBuildState()
	}
}

func (r *resourceSource) GetIdentity() identity.Identity {
	if r.r != nil {
		return r.r.(identity.IdentityProvider).GetIdentity()
	}
	return r.path
}

