		d = newTestFd()
		d.PageConfigEarly.Frontmatter["date"] = d2
		c.Assert(handler.HandleDates(d), qt.IsNil)
		c.Assert(d.PageConfigLate.Dates.Date, qt.Equals, d2)
		c.Assert(d.PageConfigLate.Params["date"], qt.Equals, d2)

	}
}

