	d := newTestFd()
	d.PageConfigEarly.Frontmatter["mydate"] = testDate
	d.PageConfigEarly.Frontmatter["date"] = testDate.Add(1 * 24 * time.Hour)
	d.PageConfigEarly.Frontmatter["mypubdate"] = testDate.Add(2 * 24 * time.Hour)
